WITH toDate('2024-07-01') AS peak_month SELECT OriginCode, count() AS flight_volume, sum(DepDelayMinutes) AS total_departure_delay_minutes, round(avg(DepDelay), 2) AS avg_departure_delay_minutes, round(avg(DepDel15) * 100, 2) AS pct_departing_15_plus_late FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND DepDelay IS NOT NULL AND toStartOfMonth(FlightDate) = peak_month GROUP BY OriginCode HAVING flight_volume >= 1000 ORDER BY total_departure_delay_minutes DESC, avg_departure_delay_minutes DESC LIMIT 20
